"use client";

import { useState } from "react";
import { ref, uploadBytes } from "firebase/storage";
import { storage } from "../lib/firebase";

export default function TestUploader() {
  const [status, setStatus] = useState("Idle");

  const handleUpload = async () => {
    setStatus("Uploading…");

    try {
      const fileRef = ref(storage, `test/test-upload-${Date.now()}.txt`);
      const file = new Blob(["Hello ProofPoint!"], { type: "text/plain" });

      await uploadBytes(fileRef, file);
      setStatus("✅ Upload successful!");
      alert("Upload complete ✅");
    } catch (err) {
      console.error(err);
      setStatus("❌ Upload failed. Check console.");
      alert("Upload failed ❌");
    }
  };

  return (
    <div style={{ padding: 20, border: "1px solid #ccc", marginBottom: 24 }}>
      <h2>🔥 Test Upload Component</h2>
      <button onClick={handleUpload} style={{ padding: "10px 20px", fontSize: 16 }}>
        Upload Test File
      </button>
      <p>Status: {status}</p>
    </div>
  );
}